import api from "./axios";

export const getSales = () => api.get("/sales");
export const getSaleById = (id) => api.get(`/sales/${id}`);

export const addSale = (data) => api.post("/sales", data);         // admin/manager
export const updateSale = (id, data) => api.put(`/sales/${id}`, data); // admin/manager
export const deleteSale = (id) => api.delete(`/sales/${id}`);      // admin/manager
